// Weekly fortune content pillar (gentle + render)
// Placeholder mode: we will later replace with real BaZi payload from Zoho Creator.

const now = new Date();

// Compute next Monday 12:00 local as the reference time (Asia/Taipei assumed by server TZ)
const ref = new Date(now);
const day = ref.getDay(); // 0 Sun .. 6 Sat
const diffToMon = (8 - day) % 7; // days until next Mon (0 if Mon)
ref.setDate(ref.getDate() + diffToMon);
ref.setHours(12, 0, 0, 0);

// Output payload expected by the Creator-side generator (to be implemented)
return [{
  json: {
    kind: 'weekly_fortune',
    referenceLocalTime: ref.toISOString(),
    tone: 'gentle_render',
    cta: 'line_free_divination',
    channels: ['ig', 'threads', 'short_video'],
    // Placeholder: once we have BaZi API, we will include:
    // bazi: { yearPillar, monthPillar, dayPillar, hourPillar, fiveElementsBalance, notes }
    placeholder: true,
    note: 'Template workflow: replace placeholder with Zoho Creator BaZi result + final content generation.'
  }
}];
